        <nav>
            <ul>
                <li style={{listStyle: 'none'}}>
                    <Link>Home</Link>
                </li>
                <li style={{listStyle: 'none'}}>
                    <Link>Name of deck {/**Will be deck name 'deck.name' */}</Link>
                </li>
                <li style={{listStyle: 'none'}}>
                    <Link>Home</Link>
                </li>
            </ul>
        </nav>
    )
}

export default Study;
